import type { DMMF } from '@prisma/generator-helper'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  BigInt: 'bigint',
  DateTime: 'Date | string',
  Json: 'unknown',
  Bytes: 'Buffer',
}

/** Map a Prisma scalar type name to its TypeScript equivalent. */
export function mapScalarType(prismaType: string): string {
  return SCALAR_TYPE_MAP[prismaType] ?? 'unknown'
}

/** Map a DMMF field to a TypeScript type annotation. */
export function fieldToTsType(field: DMMF.Field): string {
  let tsType: string

  switch (field.kind) {
    case 'scalar':
      tsType = mapScalarType(field.type)
      break
    case 'enum':
      tsType = field.type
      break
    case 'object':
      // Relation fields reference other model interfaces
      tsType = field.type
      break
    default:
      tsType = 'unknown'
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  if (!field.isRequired && !field.isList) {
    tsType = `${tsType} | null`
  }

  return tsType
}

/** Generate a TypeScript interface from a DMMF model. */
export function generateModelInterface(model: DMMF.Model): string {
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
  const fields = scalarFields
    .map((field) => {
      const optional = !field.isRequired ? '?' : ''
      return `  ${field.name}${optional}: ${fieldToTsType(field)}`
    })
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

/** Generate a create-input interface (all fields optional except required non-id scalars). */
export function generateCreateInput(model: DMMF.Model): string {
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
  const fields = scalarFields
    .map((field) => {
      // Fields with defaults or auto-generated values are optional in create input
      const isOptional = !field.isRequired || field.hasDefaultValue || field.isGenerated || field.isUpdatedAt
      const optional = isOptional ? '?' : ''
      return `  ${field.name}${optional}: ${fieldToTsType(field)}`
    })
    .join('\n')

  return `export interface ${model.name}CreateInput {\n${fields}\n}`
}

/** Generate an update-input interface (all fields optional). */
export function generateUpdateInput(model: DMMF.Model): string {
  const scalarFields = model.fields.filter((f) => f.kind === 'scalar' || f.kind === 'enum')
  const fields = scalarFields.map((field) => `  ${field.name}?: ${fieldToTsType(field)}`).join('\n')

  return `export interface ${model.name}UpdateInput {\n${fields}\n}`
}

/** Generate a where-unique input for a model based on its id/unique fields. */
export function generateWhereUniqueInput(model: DMMF.Model): string {
  const uniqueFields = model.fields.filter((f) => f.isId || f.isUnique)

  if (uniqueFields.length === 0) {
    // Fall back to all scalar fields as optional filters
    const scalarFields = model.fields.filter((f) => f.kind === 'scalar')
    const fields = scalarFields.map((f) => `  ${f.name}?: ${fieldToTsType(f)}`).join('\n')
    return `export interface ${model.name}WhereUniqueInput {\n${fields}\n}`
  }

  const fields = uniqueFields.map((f) => `  ${f.name}?: ${fieldToTsType(f)}`).join('\n')
  return `export interface ${model.name}WhereUniqueInput {\n${fields}\n}`
}

/** Generate enum type declaration. */
export function generateEnum(enumDef: DMMF.DatamodelEnum): string {
  const values = enumDef.values.map((v) => `  ${v.name} = '${v.name}'`).join(',\n')
  return `export enum ${enumDef.name} {\n${values},\n}`
}

/** Convert a model name to a URL-friendly resource path segment. */
export function modelToResourcePath(modelName: string): string {
  // Simple pluralization: lowercase first letter, append 's'
  return modelName.charAt(0).toLowerCase() + modelName.slice(1) + 's'
}

/** Generate typed CRUD methods for a single model. */
export function generateModelClient(model: DMMF.Model): string {
  const name = model.name
  const resource = modelToResourcePath(name)

  return `export function create${name}Client(baseUrl: string, options?: RequestInit) {
  const resourceUrl = \`\${baseUrl}/${resource}\`
  const defaultHeaders = { 'Content-Type': 'application/json', ...options?.headers }

  return {
    async findMany(params?: { skip?: number; take?: number }): Promise<${name}[]> {
      const query = new URLSearchParams()
      if (params?.skip !== undefined) query.set('skip', String(params.skip))
      if (params?.take !== undefined) query.set('take', String(params.take))
      const qs = query.toString()
      const url = qs ? \`\${resourceUrl}?\${qs}\` : resourceUrl
      const response = await fetch(url, { ...options, method: 'GET', headers: defaultHeaders })
      if (!response.ok) throw new RestClientError(\`Failed to fetch ${name} list\`, response)
      return response.json() as Promise<${name}[]>
    },

    async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
      const id = ${generateIdExtractor(model)}
      const response = await fetch(\`\${resourceUrl}/\${encodeURIComponent(String(id))}\`, {
        ...options,
        method: 'GET',
        headers: defaultHeaders,
      })
      if (response.status === 404) return null
      if (!response.ok) throw new RestClientError(\`Failed to fetch ${name}\`, response)
      return response.json() as Promise<${name}>
    },

    async create(data: ${name}CreateInput): Promise<${name}> {
      const response = await fetch(resourceUrl, {
        ...options,
        method: 'POST',
        headers: defaultHeaders,
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new RestClientError(\`Failed to create ${name}\`, response)
      return response.json() as Promise<${name}>
    },

    async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
      const id = ${generateIdExtractor(model)}
      const response = await fetch(\`\${resourceUrl}/\${encodeURIComponent(String(id))}\`, {
        ...options,
        method: 'PATCH',
        headers: defaultHeaders,
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new RestClientError(\`Failed to update ${name}\`, response)
      return response.json() as Promise<${name}>
    },

    async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
      const id = ${generateIdExtractor(model)}
      const response = await fetch(\`\${resourceUrl}/\${encodeURIComponent(String(id))}\`, {
        ...options,
        method: 'DELETE',
        headers: defaultHeaders,
      })
      if (!response.ok) throw new RestClientError(\`Failed to delete ${name}\`, response)
      return response.json() as Promise<${name}>
    },
  }
}`
}

function generateIdExtractor(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId)
  if (idField) {
    return `where.${idField.name}`
  }

  const uniqueField = model.fields.find((f) => f.isUnique)
  if (uniqueField) {
    return `where.${uniqueField.name}`
  }

  return `Object.values(where)[0]`
}

/** Generate the full REST client file contents from a DMMF document. */
export function generateRestClientFile(dmmf: DMMF.Document): string {
  const parts: string[] = []

  parts.push(fileHeader())
  parts.push(generateRestClientError())

  for (const enumDef of dmmf.datamodel.enums) {
    parts.push(generateEnum(enumDef))
  }

  for (const model of dmmf.datamodel.models) {
    parts.push(generateModelInterface(model))
    parts.push(generateCreateInput(model))
    parts.push(generateUpdateInput(model))
    parts.push(generateWhereUniqueInput(model))
    parts.push(generateModelClient(model))
  }

  parts.push(generateClientFactory(dmmf.datamodel.models))

  return parts.join('\n\n') + '\n'
}

function fileHeader(): string {
  return `// Generated by @prisma/generator-rest-client — do not edit manually.
/* eslint-disable */`
}

function generateRestClientError(): string {
  return `export class RestClientError extends Error {
  readonly response: Response

  constructor(message: string, response: Response) {
    super(\`\${message}: \${response.status} \${response.statusText}\`)
    this.name = 'RestClientError'
    this.response = response
  }
}`
}

/** Generate a top-level factory that creates clients for all models. */
function generateClientFactory(models: readonly DMMF.Model[]): string {
  const properties = models
    .map((model) => {
      const camelName = model.name.charAt(0).toLowerCase() + model.name.slice(1)
      return `    ${camelName}: create${model.name}Client(baseUrl, options)`
    })
    .join(',\n')

  return `export function createRestClient(baseUrl: string, options?: RequestInit) {
  return {
${properties},
  }
}

export type RestClient = ReturnType<typeof createRestClient>`
}

