 */
export function generateRestClient(options: GeneratorOptions): string {
  return generateRestClientFile(options.dmmf)
}

/** Handler for the generator protocol's `onGenerate` callback. */
export async function onGenerate(options: GeneratorOptions): Promise<void> {
  const outputDir = resolveOutputDir(options)
  const content = generateRestClientFile(options.dmmf)

  await fs.promises.mkdir(outputDir, { recursive: true })
  await fs.promises.writeFile(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}

import type { DMMF } from '@prisma/generator-helper'

const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Boolean: 'boolean',
  Int: 'number',
  Float: 'number',
  Decimal: 'string',
  BigInt: 'bigint',
  DateTime: 'Date | string',
  Json: 'unknown',
  Bytes: 'Buffer',
}

/** Map a Prisma scalar type name to its TypeScript equivalent. */
export function mapScalarType(prismaType: string): string {
  return SCALAR_TYPE_MAP[prismaType] ?? 'unknown'
}

/** Map a DMMF field to a TypeScript type annotation. */
export function fieldToTsType(field: DMMF.Field): string {
  let tsType: string

  switch (field.kind) {
    case 'scalar':
      tsType = mapScalarType(field.type)
      break
    case 'enum':
      tsType = field.type
      break
    case 'object':
      // Relation fields reference other model interfaces
      tsType = field.type
      break
    default:
      tsType = 'unknown'
  }

  if (field.isList) {
    tsType = `${tsType}[]`
  }

  if (!field.isRequired && !field.isList) {
    tsType = `${tsType} | null`
  }

  return tsType
}

