      if (!response.ok) throw new RestClientError(\`Failed to fetch ${name} list\`, response)
      return response.json() as Promise<${name}[]>
    },

    async findUnique(where: ${name}WhereUniqueInput): Promise<${name} | null> {
      const id = ${generateIdExtractor(model)}
      const response = await fetch(\`\${resourceUrl}/\${encodeURIComponent(String(id))}\`, {
        ...options,
        method: 'GET',
        headers: defaultHeaders,
      })
      if (response.status === 404) return null
      if (!response.ok) throw new RestClientError(\`Failed to fetch ${name}\`, response)
      return response.json() as Promise<${name}>
    },

    async create(data: ${name}CreateInput): Promise<${name}> {
      const response = await fetch(resourceUrl, {
        ...options,
        method: 'POST',
        headers: defaultHeaders,
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new RestClientError(\`Failed to create ${name}\`, response)
      return response.json() as Promise<${name}>
    },

    async update(where: ${name}WhereUniqueInput, data: ${name}UpdateInput): Promise<${name}> {
      const id = ${generateIdExtractor(model)}
      const response = await fetch(\`\${resourceUrl}/\${encodeURIComponent(String(id))}\`, {
        ...options,
        method: 'PATCH',
        headers: defaultHeaders,
        body: JSON.stringify(data),
      })
      if (!response.ok) throw new RestClientError(\`Failed to update ${name}\`, response)
      return response.json() as Promise<${name}>
    },

    async delete(where: ${name}WhereUniqueInput): Promise<${name}> {
      const id = ${generateIdExtractor(model)}
      const response = await fetch(\`\${resourceUrl}/\${encodeURIComponent(String(id))}\`, {
        ...options,
        method: 'DELETE',
        headers: defaultHeaders,
      })
      if (!response.ok) throw new RestClientError(\`Failed to delete ${name}\`, response)
      return response.json() as Promise<${name}>
    },
  }
}`
}

function generateIdExtractor(model: DMMF.Model): string {
  const idField = model.fields.find((f) => f.isId)
  if (idField) {
    return `where.${idField.name}`
  }

  const uniqueField = model.fields.find((f) => f.isUnique)
  if (uniqueField) {
    return `where.${uniqueField.name}`
  }

  return `Object.values(where)[0]`
}

/** Generate the full REST client file contents from a DMMF document. */
export function generateRestClientFile(dmmf: DMMF.Document): string {
  const parts: string[] = []

  parts.push(fileHeader())
  parts.push(generateRestClientError())

  for (const enumDef of dmmf.datamodel.enums) {
    parts.push(generateEnum(enumDef))
  }

  for (const model of dmmf.datamodel.models) {
    parts.push(generateModelInterface(model))
    parts.push(generateCreateInput(model))
    parts.push(generateUpdateInput(model))
    parts.push(generateWhereUniqueInput(model))
    parts.push(generateModelClient(model))
  }

  parts.push(generateClientFactory(dmmf.datamodel.models))

  return parts.join('\n\n') + '\n'
}

function fileHeader(): string {
  return `// Generated by @prisma/generator-rest-client — do not edit manually.
/* eslint-disable */`
}

function generateRestClientError(): string {
  return `export class RestClientError extends Error {
  readonly response: Response

  constructor(message: string, response: Response) {
    super(\`\${message}: \${response.status} \${response.statusText}\`)
    this.name = 'RestClientError'
    this.response = response
  }
}`
}

/** Generate a top-level factory that creates clients for all models. */
function generateClientFactory(models: readonly DMMF.Model[]): string {
  const properties = models
    .map((model) => {
      const camelName = model.name.charAt(0).toLowerCase() + model.name.slice(1)
      return `    ${camelName}: create${model.name}Client(baseUrl, options)`
    })
    .join(',\n')

  return `export function createRestClient(baseUrl: string, options?: RequestInit) {
  return {
${properties},
  }
}

export type RestClient = ReturnType<typeof createRestClient>`
}

